import{_ as e,o as t,c as s,aj as n}from"./chunks/framework.DNJ2HNkG.js";const h=JSON.parse('{"title":"RealVNC在Ubuntu 22.04无法开启的问题","description":"","frontmatter":{"title":"RealVNC在Ubuntu 22.04无法开启的问题","date":"2022-08-26T15:53:37.000Z","category":"Linux","tags":["Ubuntu"]},"headers":[],"relativePath":"posts/RealVNC在Ubuntu 22.04无法开启的问题.md","filePath":"posts/RealVNC在Ubuntu 22.04无法开启的问题.md","lastUpdated":1783047625000}'),l={name:"posts/RealVNC在Ubuntu 22.04无法开启的问题.md"};function i(d,a,o,r,u,p){return t(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="_0x01-背景" tabindex="-1">0x01 背景 <a class="header-anchor" href="#_0x01-背景" aria-label="Permalink to &quot;0x01 背景&quot;">​</a></h1><p>因为折腾各种环境比较多，现在精力也有限，像以前那样玩archlinux、gentoo的已经不大可能了，甚至debian用的都少，一般都是ubuntu的lts版本，之前是18.04.现在是20.04。</p><h1 id="_0x02-遇到的问题" tabindex="-1">0x02 遇到的问题 <a class="header-anchor" href="#_0x02-遇到的问题" aria-label="Permalink to &quot;0x02 遇到的问题&quot;">​</a></h1><p>因为设备多，各种物理机、虚拟机，自己用的系统也是linux、win、mac都有，我一般都用realvnc做远程管理软件，纯局域网控制，兼容性和性能都不错。 在Ubuntu 22.04发布后，也是最近才装了下，然后发现最常用的realvnc在22.04上没法跑，一直弹认证窗，输入密码也没用。 内外网搜了一圈都没好的解决方案，后面看了下log，对比了下20.04和22.04，最后初步定位问题出在Wayland，Wayland是Ubuntu 22.04 LTS 才开始作为默认显示服务器。</p><h1 id="_0x03-解决方法" tabindex="-1">0x03 解决方法 <a class="header-anchor" href="#_0x03-解决方法" aria-label="Permalink to &quot;0x03 解决方法&quot;">​</a></h1><p>改vnc来适配Wayland短期肯定搞不定，还是等厂商来解决吧，作为一个使用者，最简单的方法就是禁用Wayland。 Ubuntu 22.04默认的登录管理还是gdm3，所以可以通过修改gdm3配置文件来处理，方法也很简单，将<code>WaylandEnable</code>改成<code>false</code>就可以了。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sed</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s/^#.*WaylandEnable=.*/WaylandEnable=false/&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/gdm3/custom.conf</span></span></code></pre></div><p>改完后，重新启动，就可以愉快的玩耍了。</p>',8)])])}const _=e(l,[["render",i]]);export{h as __pageData,_ as default};
